As an AI text model, I cannot directly render or display a 3D image. However, I can provide you with the **code** to generate a 3D house using **Three.js** (a popular JavaScript library for 3D graphics on the web).

You can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any modern web browser to see the 3D model.

### 3D House Generator (Three.js)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click and drag to rotate • Scroll to zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 10, 50);

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(5, 5, 10);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x555555 }); // Grey
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.3 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x333333 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x228B22 });

        // 5. Geometry Construction
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeo = new THREE.BoxGeometry(8, 4, 8);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 2;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 6;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows (Simple planes)
        function createWindow(x, z, y, w, h) {
            const geo = new THREE.PlaneGeometry(w, h);
            const mesh = new THREE.Mesh(geo, windowMaterial);
            mesh.position.set(x, y, z);
            mesh.rotation.y = Math.PI; // Face inward
            houseGroup.add(mesh);
        }

        createWindow(2, 2, 3.9, 2, 1.5);
        createWindow(-2, 2, 3.9, 2, 1.5);
        createWindow(0, 2, 3.9, 2, 1.5); // Front door area window

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 1, 3.9);
        houseGroup.add(door);

        // Chimney
        const chimneyGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimneyGeo, wallMaterial);
        chimney.position.set(3, 8, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        // Trees
        function createTree(x, z) {
            const trunkGeo = new THREE.CylinderGeometry(0.5, 0.8, 2, 8);
            const trunk = new THREE.Mesh(trunkGeo, new THREE.MeshStandardMaterial({color: 0x8B4513}));
            trunk.position.set(x, 1, z);
            trunk.castShadow = true;

            const leavesGeo = new THREE.DodecahedronGeometry(2);
            const leaves = new THREE.Mesh(leavesGeo, new THREE.MeshStandardMaterial({color: 0x006400}));
            leaves.position.set(x, 3, z);
            leaves.castShadow = true;

            return new THREE.Group().add(trunk).add(leaves);
        }

        scene.add(createTree(-6, -6));
        scene.add(createTree(6, -6));
        scene.add(createTree(-6, 6));
        scene.add(createTree(6, 6));

        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Copy** the code block above.
2.  Create a new file on your computer named `house.html`.
3.  **Paste** the code into that file and save it.
4.  **Double-click** `house.html` to open it in Chrome, Firefox, Safari, or Edge.

### Features of this model:
*   **Interactive:** You can click and drag to rotate the camera, scroll to zoom in/out, and right-click to pan.
*   **Lighting:** Includes shadows and a directional light (sun) to give it depth.
*   **Environment:** Includes a grass floor, sky background, fog, and simple trees.
*   **No Installation Required:** It loads the 3D engine directly from the internet (CDN), so you don't need to install Node.js or any software.
